{
  "id": "automation-001-setup-cronjob",
  "title": "Set Up Cronjob on Mittwald",
  "description": "Set up a scheduled cronjob on Mittwald hosting.",
  "domain": "automation",
  "prompt": "I need to set up a cronjob on my Mittwald project. Use the Mittwald MCP tools to first list my projects and existing cronjobs, then show me the cronjob details.",
  "expectedDomains": ["automation", "project-foundation"],
  "expectedTools": [
    "mcp__mittwald__mittwald_project_list",
    "mcp__mittwald__mittwald_cronjob_list"
  ],
  "successCriteria": [
    {
      "description": "Cronjob or project tools used",
      "method": "log-pattern",
      "config": {
        "pattern": "mcp__mittwald__mittwald_(cronjob|project)",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [],
  "questionAnswers": [
    { "questionPattern": "which project", "answer": "My main website project" },
    { "questionPattern": "schedule|time", "answer": "Every day at 3:00 AM" }
  ],
  "estimatedDuration": 4,
  "timeout": 12,
  "priority": "P2",
  "tags": ["automation", "cronjob", "mittwald"]
}

{
  "id": "automation-002-manage-scheduled-tasks",
  "title": "Manage Scheduled Tasks on Mittwald",
  "description": "Review and manage cronjobs on Mittwald hosting.",
  "domain": "automation",
  "prompt": "I want to review all the scheduled cronjobs on my Mittwald project. Use the Mittwald MCP tools to list all cronjobs and show their execution history.",
  "expectedDomains": ["automation", "project-foundation"],
  "expectedTools": [
    "mcp__mittwald__mittwald_project_list",
    "mcp__mittwald__mittwald_cronjob_list",
    "mcp__mittwald__mittwald_cronjob_execution_list"
  ],
  "successCriteria": [
    {
      "description": "Cronjob tools used",
      "method": "log-pattern",
      "config": {
        "pattern": "mcp__mittwald__mittwald_cronjob",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [],
  "questionAnswers": [
    { "questionPattern": "which project", "answer": "The production website" }
  ],
  "estimatedDuration": 3,
  "timeout": 10,
  "priority": "P3",
  "tags": ["automation", "cronjob", "monitoring", "mittwald"]
}

